type UnescapedCookieParamError struct {
	ParamName string
	Err       error
}

func (e *UnescapedCookieParamError) Error() string {
	return fmt.Sprintf("error unescaping cookie parameter '%s'", e.ParamName)
}

func (e *UnescapedCookieParamError) Unwrap() error {
	return e.Err
}

type UnmarshalingParamError struct {
	ParamName string
	Err       error
}

func (e *UnmarshalingParamError) Error() string {
	return fmt.Sprintf("Error unmarshaling parameter %s as JSON: %s", e.ParamName, e.Err.Error())
}

func (e *UnmarshalingParamError) Unwrap() error {
	return e.Err
}

type RequiredParamError struct {
	ParamName string
}

func (e *RequiredParamError) Error() string {
	return fmt.Sprintf("Query argument %s is required, but not found", e.ParamName)
}

type RequiredHeaderError struct {
	ParamName string
	Err       error
}

func (e *RequiredHeaderError) Error() string {
	return fmt.Sprintf("Header parameter %s is required, but not found", e.ParamName)
}

func (e *RequiredHeaderError) Unwrap() error {
	return e.Err
}

type InvalidParamFormatError struct {
	ParamName string
	Err       error
}

func (e *InvalidParamFormatError) Error() string {
	return fmt.Sprintf("Invalid format for parameter %s: %s", e.ParamName, e.Err.Error())
}

func (e *InvalidParamFormatError) Unwrap() error {
	return e.Err
}

type TooManyValuesForParamError struct {
	ParamName string
	Count     int
}

func (e *TooManyValuesForParamError) Error() string {
	return fmt.Sprintf("Expected one value for %s, got %d", e.ParamName, e.Count)
}

// Handler creates http.Handler with routing matching OpenAPI spec.
func Handler(si ServerInterface) http.Handler {
	return HandlerWithOptions(si, StdHTTPServerOptions{})
}

// ServeMux is an abstraction of http.ServeMux.
type ServeMux interface {
	HandleFunc(pattern string, handler func(http.ResponseWriter, *http.Request))
	ServeHTTP(w http.ResponseWriter, r *http.Request)
}

type StdHTTPServerOptions struct {
	BaseURL          string
	BaseRouter       ServeMux
	Middlewares      []MiddlewareFunc
	ErrorHandlerFunc func(w http.ResponseWriter, r *http.Request, err error)
}

// HandlerFromMux creates http.Handler with routing matching OpenAPI spec based on the provided mux.
func HandlerFromMux(si ServerInterface, m ServeMux) http.Handler {
	return HandlerWithOptions(si, StdHTTPServerOptions{
		BaseRouter: m,
	})
}

func HandlerFromMuxWithBaseURL(si ServerInterface, m ServeMux, baseURL string) http.Handler {
	return HandlerWithOptions(si, StdHTTPServerOptions{
		BaseURL:    baseURL,
		BaseRouter: m,
	})
}

// HandlerWithOptions creates http.Handler with additional options
func HandlerWithOptions(si ServerInterface, options StdHTTPServerOptions) http.Handler {
	m := options.BaseRouter

	if m == nil {
		m = http.NewServeMux()
	}
	if options.ErrorHandlerFunc == nil {
		options.ErrorHandlerFunc = func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusBadRequest)
		}
	}

	wrapper := ServerInterfaceWrapper{
		Handler:            si,
		HandlerMiddlewares: options.Middlewares,
		ErrorHandlerFunc:   options.ErrorHandlerFunc,
	}

	m.HandleFunc("GET "+options.BaseURL+"/v1/analytics/summary", wrapper.GetAnalyticsSummary)
	m.HandleFunc("GET "+options.BaseURL+"/v1/approvals", wrapper.ListApprovals)
	m.HandleFunc("GET "+options.BaseURL+"/v1/approvals/{approval_id}", wrapper.GetApproval)
	m.HandleFunc("POST "+options.BaseURL+"/v1/approvals/{approval_id}/approve", wrapper.ApproveRequest)
	m.HandleFunc("POST "+options.BaseURL+"/v1/approvals/{approval_id}/deny", wrapper.DenyRequest)
	m.HandleFunc("POST "+options.BaseURL+"/v1/approvals/{approval_id}/modify", wrapper.ModifyRequest)
	m.HandleFunc("GET "+options.BaseURL+"/v1/connectors", wrapper.ListConnectors)
	m.HandleFunc("POST "+options.BaseURL+"/v1/connectors", wrapper.CreateConnector)
	m.HandleFunc("GET "+options.BaseURL+"/v1/connectors/{connector_id}", wrapper.GetConnector)
	m.HandleFunc("PATCH "+options.BaseURL+"/v1/connectors/{connector_id}", wrapper.UpdateConnector)
	m.HandleFunc("GET "+options.BaseURL+"/v1/credentials", wrapper.ListCredentials)
	m.HandleFunc("POST "+options.BaseURL+"/v1/credentials", wrapper.CreateCredential)
	m.HandleFunc("GET "+options.BaseURL+"/v1/execution-grants/{grant_id}", wrapper.GetExecutionGrant)
	m.HandleFunc("POST "+options.BaseURL+"/v1/executions/run", wrapper.RunExecution)
	m.HandleFunc("GET "+options.BaseURL+"/v1/executions/{execution_id}", wrapper.GetExecution)
	m.HandleFunc("POST "+options.BaseURL+"/v1/executions/{execution_id}/callback", wrapper.ExecutionCallback)
	m.HandleFunc("GET "+options.BaseURL+"/v1/funding-sources", wrapper.ListFundingSources)
	m.HandleFunc("POST "+options.BaseURL+"/v1/funding-sources", wrapper.CreateFundingSource)
	m.HandleFunc("GET "+options.BaseURL+"/v1/health", wrapper.GetHealth)
	m.HandleFunc("GET "+options.BaseURL+"/v1/intents", wrapper.ListIntents)
	m.HandleFunc("POST "+options.BaseURL+"/v1/intents", wrapper.CreateIntent)
	m.HandleFunc("GET "+options.BaseURL+"/v1/intents/{intent_id}", wrapper.GetIntent)
	m.HandleFunc("POST "+options.BaseURL+"/v1/intents/{intent_id}/evidence", wrapper.AppendIntentEvidence)
	m.HandleFunc("GET "+options.BaseURL+"/v1/policies", wrapper.ListPolicies)
	m.HandleFunc("POST "+options.BaseURL+"/v1/policies", wrapper.CreatePolicy)
	m.HandleFunc("POST "+options.BaseURL+"/v1/policies/simulate", wrapper.SimulatePolicy)
	m.HandleFunc("GET "+options.BaseURL+"/v1/policies/{policy_id}", wrapper.GetPolicy)
	m.HandleFunc("PATCH "+options.BaseURL+"/v1/policies/{policy_id}", wrapper.UpdatePolicy)
	m.HandleFunc("GET "+options.BaseURL+"/v1/traces", wrapper.ListTraces)

	return m
}

